 61	// Combine bytes in - little-endian format
 62	int combine_bytes(const uint8_t *bytes, size_t num_bytes)
 63	{
 64	  int result = 0;
 65	  for (size_t i = 0; i < num_bytes; ++i) {
 66	    result |= (bytes[i] << (i * 8));
 67	  }
 68	  return result;
 69	}
 70	
 71	// Convert an integer to an array of bytes - little-endian format
 72	void int_to_bytes(int num, uint8_t *bytes, size_t num_bytes)
 73	{
 74	  for (size_t i = 0; i < num_bytes; ++i) {
 75	    bytes[i] = (num >> (i * 8)) & 0xFF;
 76	  }
 77	}
