 90	// Get the current time
 91	struct timespec get_current_time()
 92	{
 93	  struct timespec time;
 94	  clock_gettime(CLOCK_MONOTONIC, &time);
 95	  return time;
 96	}
 97	
 98	// Function to convert timespec to microseconds
 99	long long timespec_to_microseconds(struct timespec time)
100	{
101	  return (time.tv_sec * 1000000LL) + (time.tv_nsec / 1000);
102	}
103	
104	// Calculate the time difference in milliseconds
105	double calculate_time_difference(struct timespec start, struct timespec end)
106	{
107	  double start_ms = start.tv_sec * 1000.0 + start.tv_nsec / 1000000.0;
108	  double end_ms = end.tv_sec * 1000.0 + end.tv_nsec / 1000000.0;
109	  return end_ms - start_ms;
110	}
