112	// Get Time Stamp in microseconds in YYYYMMDDHHMMSSmmmuuu format
113	char *get_time_stamp_usec(char time_stamp_str[])
114	{
115	  // initialization to measure time stamp --This part should be moved to inilization part
116	  time_t my_time;
117	  struct tm *timeinfo;
118	  time(&my_time);
119	  struct timeval tv;
120	
121	  // get time stamp
122	  timeinfo = localtime(&my_time);
123	  gettimeofday(&tv, NULL);
124	  // Add time stamp: yyyy mm dd hh mm ss usec
125	  uint16_t year = timeinfo->tm_year + 1900;
126	  uint8_t mon = timeinfo->tm_mon + 1;
127	  uint8_t mday = timeinfo->tm_mday;
128	  uint8_t hour = timeinfo->tm_hour;
129	  uint8_t min = timeinfo->tm_min;
130	  uint8_t sec = timeinfo->tm_sec;
131	  uint16_t usec = (tv.tv_usec);
132	  // printf ("Time stamp: %d_%d_%d_%d_%d_%d_%d \n",year,mon,mday,hour,min,sec,usec);
133	  // sprintf(time_stamp_str, "%d_%d_%d_%d_%d_%d_%d",year,mon,mday,hour,min,sec,usec);
134	  sprintf(time_stamp_str, "%04d%02d%02d%02d%02d%02d%06d", year, mon, mday, hour, min, sec, usec);
135	
136	  return time_stamp_str;
137	}
